record_types.code:
type INTERP_Peripheral is record
   ACCUM       : ACCUM_Register;
   BASE        : LANE_Register;
   POP         : LANE_Register;
   PEEK        : LANE_Register;
   CTRL        : CTRL_Register;
   ADD         : ADD_Register;
   BASE_1AND0  : UInt32;
end record;

type Lane_Config is record
   SHIFT          : UInt5   := 0;
   MASK_LSB       : UInt5   := 0;
   MASK_MSB       : UInt5   := 31;
   SIGNED         : Boolean := False;
   CROSS_INPUT    : Boolean := False;
   CROSS_RESULT   : Boolean := False;
   ADD_RAW        : Boolean := False;
   FORCE_MSB      : UInt2   := 0;
   BLEND          : Boolean := False;
   CLAMP          : Boolean := False;
   OVERF           : Boolean := False;
   OVERF1          : Boolean := False;
   OVERF0          : Boolean := False;
end record;
